package policy

import (
	"context"
	"encoding/json"
	"io"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-audit")

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes.
type PolicyAuditLogger struct {
	mu        lock.Mutex
	logLevel  logrus.Level
	output    io.Writer
	useJSON   bool
	scopedLog *logrus.Entry
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the specified
// log level. If output is nil, logs will be written to the default logger.
func NewPolicyAuditLogger(level logrus.Level, output io.Writer) *PolicyAuditLogger {
	pal := &PolicyAuditLogger{
		logLevel: level,
		output:   output,
		useJSON:  false,
	}
	pal.scopedLog = log.WithField(logfields.LogSubsys, "policy-audit")
	return pal
}

// SetJSONOutput enables or disables JSON-formatted output for audit logs.
func (pal *PolicyAuditLogger) SetJSONOutput(enabled bool) {
	pal.mu.Lock()
	defer pal.mu.Unlock()
	pal.useJSON = enabled
}

// SetLogLevel updates the log level for audit logging.
func (pal *PolicyAuditLogger) SetLogLevel(level logrus.Level) {
	pal.mu.Lock()
	defer pal.mu.Unlock()
	pal.logLevel = level
}

// LogDecision logs a policy decision with the given identity, policy, verdict, and reason.
// This is used to log individual policy verdicts during policy evaluation.
func (pal *PolicyAuditLogger) LogDecision(identity identity.NumericIdentity, policy string, verdict string, reason string) {
	pal.mu.Lock()
	defer pal.mu.Unlock()

	if !pal.shouldLog() {
		return
	}

	fields := logrus.Fields{
		logfields.Identity: identity,
		"policy":           policy,
		"verdict":          verdict,
		logfields.Reason:   reason,
	}

	if pal.useJSON {
		pal.logJSON("policy_decision", fields)
	} else {
		pal.scopedLog.WithFields(fields).Logf(pal.logLevel, "Policy decision: %s", verdict)
	}
}

// LogEvaluation logs a policy evaluation result with context about which
// policy was evaluated, the selector cache state, and the result.
// ctx is the evaluation context, policyKey is the policy identifier,
// selectorCache is the cache used for identity selection, and result
// is the evaluation outcome.
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey string, selectorCache *SelectorCache, result string) {
	pal.mu.Lock()
	defer pal.mu.Unlock()

	if !pal.shouldLog() {
		return
	}

	fields := logrus.Fields{
		logfields.PolicyKey: policyKey,
		"result":            result,
	}

	// If context contains trace information, include it
	if ctx != nil {
		if deadline, ok := ctx.Deadline(); ok {
			fields["deadline"] = deadline
		}
	}

	if pal.useJSON {
		pal.logJSON("policy_evaluation", fields)
	} else {
		pal.scopedLog.WithFields(fields).Logf(pal.logLevel, "Policy evaluation: %s", result)
	}
}

// shouldLog determines if a log entry should be written based on the
// configured log level and the logger's log level.
func (pal *PolicyAuditLogger) shouldLog() bool {
	return logging.CanLogAt(log.Logger, pal.logLevel)
}

// logJSON writes a JSON-formatted audit log entry.
func (pal *PolicyAuditLogger) logJSON(eventType string, fields logrus.Fields) {
	entry := map[string]interface{}{
		"event_type": eventType,
		"fields":     fields,
	}

	jsonData, err := json.Marshal(entry)
	if err != nil {
		pal.scopedLog.WithError(err).Warn("Failed to marshal audit log entry to JSON")
		return
	}

	if pal.output != nil {
		_, err = pal.output.Write(append(jsonData, '\n'))
		if err != nil {
			pal.scopedLog.WithError(err).Warn("Failed to write audit log to output")
		}
	} else {
		pal.scopedLog.WithField("json_entry", string(jsonData)).Logf(pal.logLevel, "Audit log entry")
	}
}

