	output := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.DebugLevel, output)
	logger.SetJSONOutput(true)

	ctx := context.Background()
	testPolicyKey := "test-policy-key"
	testResult := "success"

	logger.LogEvaluation(ctx, testPolicyKey, nil, testResult)

